const body = $input.item.json.body || $input.item.json;
const query = $input.item.json.query || {};

// account_id pode vir na query string ou no body
const account_id = query.account_id || body.account_id;

if (!account_id) throw new Error('account_id não informado');

// Suporte a diferentes formatos de payload do Meta
// Formato 1: campo direto { name, phone, email }
// Formato 2: field_data array (Lead Ads nativo)
let name, phone, email, source;

if (body.field_data && Array.isArray(body.field_data)) {
  const get = (key) => {
    const f = body.field_data.find(f => f.name === key);
    return f ? f.values[0] : null;
  };
  name = get('full_name') || `${get('first_name') || ''} ${get('last_name') || ''}`.trim();
  phone = get('phone_number') || get('phone');
  email = get('email');
} else {
  name = body.name || body.full_name || body.nome;
  phone = body.phone || body.phone_number || body.telefone;
  email = body.email;
}

// Limpa telefone (só números)
phone = (phone || '').replace(/\D/g, '');

if (!name || !phone) throw new Error('name e phone são obrigatórios');

source = body.campaign_name || body.source || body.utm_campaign || 'Meta Ads';

const canal = body.canal || (body.source?.toLowerCase().includes('instagram') ? 'instagram' : 'facebook');

return [{
  json: {
    account_id,
    name,
    phone,
    email: email || null,
    canal,
    source,
  }
}];
